using Microsoft.EntityFrameworkCore;
using NetTopologySuite.Geometries;
using EdirneGeziAPI.Models;

namespace EdirneGeziAPI.Data
{
    public class GeziDbContext : DbContext
    {
        public GeziDbContext(DbContextOptions<GeziDbContext> options) : base(options) { }

        public DbSet<Category> Categories { get; set; }
        public DbSet<Place> Places { get; set; }
        public DbSet<Review> Reviews { get; set; }
        public DbSet<User> Users { get; set; }
        public DbSet<Favorite> Favorites { get; set; }
        public DbSet<PlaceSuggestion> PlaceSuggestions { get; set; }

        protected override void OnModelCreating(ModelBuilder modelBuilder)
        {
            modelBuilder.HasPostgresExtension("postgis");
            base.OnModelCreating(modelBuilder);

            modelBuilder.Entity<Favorite>()
                .HasIndex(f => new { f.UserId, f.PlaceId })
                .IsUnique();

            modelBuilder.Entity<Favorite>()
                .HasOne(f => f.User)
                .WithMany()
                .HasForeignKey(f => f.UserId)
                .OnDelete(DeleteBehavior.Cascade);

            modelBuilder.Entity<Favorite>()
                .HasOne(f => f.Place)
                .WithMany()
                .HasForeignKey(f => f.PlaceId)
                .OnDelete(DeleteBehavior.Cascade);

            modelBuilder.Entity<Category>().HasData(
                new Category { Id = 1, Name = "Tarihi Eser" },
                new Category { Id = 2, Name = "Müze" },
                new Category { Id = 3, Name = "Yöresel Lezzet" },
                new Category { Id = 4, Name = "Doğa ve Park" },
                new Category { Id = 5, Name = "Tarihi Çarşı" },
                new Category { Id = 6, Name = "Tarihi Hamam" },
                new Category { Id = 7, Name = "Etkinlik ve Festival" }
            );

